def solve(arg1: dict) -> str:
    environment = arg1.get('environment')
    logLevel = arg1.get('logLevel')
    message = arg1.get('message')

    if environment == 'development':
        if logLevel == 'info':
            return f'Console log: {message}'
        else:
            return None
    elif environment == 'production':
        if logLevel == 'error':
            return f'Console log: {message}'
        elif logLevel == 'file':
            return f'File log created with message: {message}'
        else:
            return 'No file log created'
    return None
